import{c as e,Q as r,j as o,m as s}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"最佳實踐指南","description":"","frontmatter":{},"headers":[],"relativePath":"resources/best-practices/index.md","filePath":"resources/best-practices/index.md","lastUpdated":1779796674000}'),a={name:"resources/best-practices/index.md"};function i(c,t,n,d,l,p){return r(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="最佳實踐指南" tabindex="-1">最佳實踐指南 <a class="header-anchor" href="#最佳實踐指南" aria-label="Permalink to &quot;最佳實踐指南&quot;">​</a></h1><p>本節整理自 Anthropic 官方文件、社群實踐（Boris Cherny、Thariq Shihipar 等核心貢獻者）及深度研究報告，涵蓋 Claude Code 工程化使用的各個面向。</p><h2 id="指南目錄" tabindex="-1">指南目錄 <a class="header-anchor" href="#指南目錄" aria-label="Permalink to &quot;指南目錄&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主題</th><th>說明</th></tr></thead><tbody><tr><td><a href="/cc-workspace-docs/resources/best-practices/workflows/">工作流程與核心技巧</a></td><td>Explore→Plan→Implement→Commit 四階段、Plan Mode、Session 管理、Boris Cherny 65+ 技巧</td></tr><tr><td><a href="/cc-workspace-docs/resources/best-practices/hooks/">Hooks 設計模式</a></td><td>25 種 hook 事件完整範例、PreToolUse 防禦、PostToolUse 自動化、SessionStart 初始化</td></tr><tr><td><a href="/cc-workspace-docs/resources/best-practices/permissions/">Permission 細粒度設定</a></td><td>五種 Permission Mode、Wildcard 語法、Compound 指令、Symlink 規則</td></tr><tr><td><a href="/cc-workspace-docs/resources/best-practices/mcp-skills/">MCP Server 與 Skills</a></td><td>三種 transport 安裝、OAuth 認證、Scope 管理、Skills 設計原則</td></tr><tr><td><a href="/cc-workspace-docs/resources/best-practices/prompt-caching/">Prompt Caching 工程</a></td><td>前綴匹配原理、六大教訓（Thariq）、Cache Hit Rate 監控、失效條件</td></tr></tbody></table><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><p>來自 2026-05-16 深度研究報告的結論：</p><blockquote><p><strong>Context Engineering（在執行時組裝正確資訊並正確排序）是 Claude Code 真正的工程護城河，遠比 Prompt 撰寫技巧更重要。</strong></p></blockquote><p>這五個面向都是 Context Engineering 的具體實踐：</p><ul><li><strong>Hooks</strong>：在正確的時機注入正確的行為（確定性控制）</li><li><strong>Permissions</strong>：定義清晰邊界讓 agent 自主工作（減少核准疲勞）</li><li><strong>MCP/Skills</strong>：在 context 中提供正確的工具接口（能力延伸）</li><li><strong>Prompt Caching</strong>：讓靜態 context 高效復用（成本工程）</li><li><strong>Workflows</strong>：確保每次任務都有完整的驗證反饋迴路（可靠性）</li></ul>',9)])])}const u=e(a,[["render",i]]);export{m as __pageData,u as default};
